"use client";
import { useState, useRef, useCallback, useEffect } from "react";

/* ──────────────────────── Draggable wrapper ──────────────────────── */

interface DraggableItemProps {
  left: string;
  top: string;
  rotation?: number;
  size?: number;
  children: React.ReactNode;
  className?: string;
  onGrab: () => number;
}

function DraggableItem({ left, top, rotation = 0, size, children, className, onGrab }: DraggableItemProps) {
  const [offset, setOffset] = useState({ x: 0, y: 0 });
  const [z, setZ] = useState(1);
  const [dragging, setDragging] = useState(false);
  const dragRef = useRef({ startX: 0, startY: 0, origX: 0, origY: 0 });

  const handleStart = useCallback((clientX: number, clientY: number) => {
    setZ(onGrab());
    setDragging(true);
    dragRef.current = { startX: clientX, startY: clientY, origX: offset.x, origY: offset.y };
  }, [onGrab, offset]);

  useEffect(() => {
    if (!dragging) return;
    const handleMove = (e: MouseEvent | TouchEvent) => {
      const pt = "touches" in e ? e.touches[0] : e;
      setOffset({
        x: dragRef.current.origX + pt.clientX - dragRef.current.startX,
        y: dragRef.current.origY + pt.clientY - dragRef.current.startY,
      });
    };
    const handleEnd = () => setDragging(false);
    window.addEventListener("mousemove", handleMove);
    window.addEventListener("mouseup", handleEnd);
    window.addEventListener("touchmove", handleMove, { passive: false });
    window.addEventListener("touchend", handleEnd);
    return () => {
      window.removeEventListener("mousemove", handleMove);
      window.removeEventListener("mouseup", handleEnd);
      window.removeEventListener("touchmove", handleMove);
      window.removeEventListener("touchend", handleEnd);
    };
  }, [dragging]);

  return (
    <div
      className={`draggable-item${dragging ? " dragging" : ""} ${className ?? ""}`}
      style={{
        left,
        top,
        width: size ? `${size}px` : undefined,
        zIndex: z,
        transform: `translate(${offset.x}px, ${offset.y}px) rotate(${rotation}deg)`,
      }}
      onMouseDown={(e) => { e.preventDefault(); handleStart(e.clientX, e.clientY); }}
      onTouchStart={(e) => { handleStart(e.touches[0].clientX, e.touches[0].clientY); }}
    >
      {children}
    </div>
  );
}

